You are an interface derivation agent. Given a frozen Stage 1 decomposition, your task is to derive precise typed interfaces for each child.

RULES:
1. You MUST NOT add, delete, rename, or reorder children. The child list from Stage 1 is LOCKED.
2. You MUST NOT change any Stage 1 field (purpose, behavior, boundary, preconditions, postconditions, guarantees, composition_role).
3. Derive ONLY interface fields.
4. Separate parent-call parameters from internal leaf resource access.

REQUIRED INTERFACE CATEGORIES:
- call_inputs: Parameters the parent must pass when calling this child. Only these may appear in the Python signature.
- internal_leaf_accesses: Resources/data stores this child accesses inside its own implementation. These must NOT appear in the Python signature.
- outputs: Values returned by the child to the parent.
- signature: Python function signature built only from call_inputs.

DATAFLOW RULES:
- from_node and to_node must be either "parent" or an exact child name.
- Resource/store names such as raw_data, processed_data, channels, messages, orders, inventory, or payments must NOT appear as from_node/to_node.

OUTPUT FORMAT — Return valid JSON:
{
  "children": [
    {
      "name": "UNCHANGED from Stage 1",
      "purpose": "UNCHANGED",
      "behavior": "UNCHANGED",
      "boundary": {"in_scope": ["UNCHANGED"], "out_of_scope": ["UNCHANGED"]},
      "semantic_inputs": ["UNCHANGED"],
      "semantic_outputs": ["UNCHANGED"],
      "preconditions": ["UNCHANGED"],
      "postconditions": ["UNCHANGED"],
      "guarantees": ["UNCHANGED"],
      "composition_role": "UNCHANGED",
      "stop_decompose": false,
      "stop_reason": "",
      "call_inputs": [
        {"name": "param", "type": "dict", "description": "what parent passes", "source": "parent input | previous child output | constant"}
      ],
      "internal_leaf_accesses": [
        {"resource": "resource_name", "op": "read|write|read_write", "reason": "why this child needs the resource internally"}
      ],
      "outputs": [
        {"name": "result", "type": "dict", "description": "what child returns", "consumer": "parent"}
      ],
      "signature": "def ChildName(param: type) -> return_type"
    }
  ],
  "interface_preservation": {
    "parent_inputs_covered_by": {"input_name": "child_name"},
    "parent_outputs_produced_by": {"output_name": "child_name"}
  },
  "dataflow_edges": [
    {"from_node": "parent | ChildName", "from_output": "output_name", "to_node": "ChildName | parent", "to_input": "input_name", "note": "why"}
  ],
  "interface_audit": {
    "identity_preservation_detail": "explain whether child names/order are preserved",
    "semantic_preservation_detail": "explain whether Stage1 semantics are unchanged",
    "call_signature_detail": "explain why signature contains only call_inputs",
    "internal_leaf_separation_detail": "explain why resources are not call params",
    "dataflow_schema_detail": "explain endpoint legality",
    "final_status": "ok | needs_attention"
  }
}

{
  "children": [
    {
      "name": "ParseInput",
      "purpose": "Parse and validate the input JSON to extract action, repo, branch",
      "behavior": "Parse JSON input, validate required fields, return structured action request",
      "boundary": {
        "in_scope": [
          "JSON parsing",
          "field validation"
        ],
        "out_of_scope": [
          "executing any action",
          "accessing data stores"
        ]
      },
      "semantic_inputs": [
        {
          "name": "input",
          "description": "Raw JSON input",
          "source": "parent input"
        }
      ],
      "semantic_outputs": [
        {
          "name": "action_request",
          "description": "Parsed action request with action, repo, branch",
          "consumer": "parent"
        }
      ],
      "preconditions": [
        "input is valid JSON"
      ],
      "postconditions": [
        "action_request contains valid action, repo, branch"
      ],
      "guarantees": [
        "returns error if input invalid"
      ],
      "composition_role": "transform",
      "stop_decompose": true,
      "stop_reason": "pure parsing function"
    },
    {
      "name": "RouteAction",
      "purpose": "Route the action to the appropriate child function based on action type",
      "behavior": "Based on action_request.action, call the corresponding child function",
      "boundary": {
        "in_scope": [
          "action routing",
          "invoking children"
        ],
        "out_of_scope": [
          "implementing action logic"
        ]
      },
      "semantic_inputs": [
        {
          "name": "action_request",
          "description": "Parsed action request",
          "source": "ParseInput output"
        }
      ],
      "semantic_outputs": [
        {
          "name": "action_result",
          "description": "Result from the executed action",
          "consumer": "parent"
        }
      ],
      "preconditions": [
        "action_request is valid"
      ],
      "postconditions": [
        "appropriate child function called"
      ],
      "guarantees": [
        "only one child function called per request"
      ],
      "composition_role": "decide",
      "stop_decompose": true,
      "stop_reason": "pure routing logic"
    },
    {
      "name": "TriggerBuild",
      "purpose": "Trigger a new build for a given repo and branch",
      "behavior": "Check if build already exists for repo+branch, if not create new build record, return build_id",
      "boundary": {
        "in_scope": [
          "build creation",
          "duplicate check"
        ],
        "out_of_scope": [
          "cancelling builds",
          "listing builds"
        ]
      },
      "semantic_inputs": [
        {
          "name": "repo",
          "description": "Repository name",
          "source": "action_request"
        },
        {
          "name": "branch",
          "description": "Branch name",
          "source": "action_request"
        }
      ],
      "semantic_outputs": [
        {
          "name": "build_result",
          "description": "JSON with success, build_id",
          "consumer": "parent"
        }
      ],
      "preconditions": [
        "build does not already exist for repo+branch"
      ],
      "postconditions": [
        "new build record created in builds store"
      ],
      "guarantees": [
        "build_id is unique"
      ],
      "composition_role": "execute",
      "stop_decompose": false,
      "stop_reason": "can be further decomposed"
    },
    {
      "name": "CheckStatus",
      "purpose": "Check the status of a specific build",
      "behavior": "Look up build by repo and branch, return status and logs",
      "boundary": {
        "in_scope": [
          "build lookup",
          "status retrieval"
        ],
        "out_of_scope": [
          "triggering",
          "cancelling"
        ]
      },
      "semantic_inputs": [
        {
          "name": "repo",
          "description": "Repository name",
          "source": "action_request"
        },
        {
          "name": "branch",
          "description": "Branch name",
          "source": "action_request"
        }
      ],
      "semantic_outputs": [
        {
          "name": "build_result",
          "description": "JSON with success, status, logs",
          "consumer": "parent"
        }
      ],
      "preconditions": [
        "build exists for repo+branch"
      ],
      "postconditions": [
        "status and logs returned"
      ],
      "guarantees": [
        "returns error if build not found"
      ],
      "composition_role": "query",
      "stop_decompose": true,
      "stop_reason": "simple lookup"
    },
    {
      "name": "ListBuilds",
      "purpose": "List all builds for a given repo",
      "behavior": "Query builds store for all builds matching repo, return list of build summaries",
      "boundary": {
        "in_scope": [
          "build listing",
          "filtering by repo"
        ],
        "out_of_scope": [
          "individual build details"
        ]
      },
      "semantic_inputs": [
        {
          "name": "repo",
          "description": "Repository name",
          "source": "action_request"
        }
      ],
      "semantic_outputs": [
        {
          "name": "build_result",
          "description": "JSON with success, list of builds",
          "consumer": "parent"
        }
      ],
      "preconditions": [
        "none"
      ],
      "postconditions": [
        "list of builds returned"
      ],
      "guarantees": [
        "returns empty list if no builds"
      ],
      "composition_role": "query",
      "stop_decompose": true,
      "stop_reason": "simple query"
    },
    {
      "name": "CancelBuild",
      "purpose": "Cancel a running build",
      "behavior": "Find build by repo+branch, update status to cancelled, return success",
      "boundary": {
        "in_scope": [
          "build cancellation",
          "status update"
        ],
        "out_of_scope": [
          "triggering",
          "listing"
        ]
      },
      "semantic_inputs": [
        {
          "name": "repo",
          "description": "Repository name",
          "source": "action_request"
        },
        {
          "name": "branch",
          "description": "Branch name",
          "source": "action_request"
        }
      ],
      "semantic_outputs": [
        {
          "name": "build_result",
          "description": "JSON with success",
          "consumer": "parent"
        }
      ],
      "preconditions": [
        "build exists and is not already cancelled"
      ],
      "postconditions": [
        "build status set to cancelled"
      ],
      "guarantees": [
        "idempotent if already cancelled"
      ],
      "composition_role": "mutate",
      "stop_decompose": true,
      "stop_reason": "simple state mutation"
    }
  ],
  "decomposition_rationale": "The parent BuildSystem is decomposed into a parsing step, a routing decision, and four action-specific children (trigger, status, list, cancel). This covers all functional requirements without overlapping responsibilities.",
  "orchestration_model": "sequence with conditional branching",
  "dataflow_sketch": [
    {
      "from": "parent",
      "to": "ParseInput",
      "data": "input",
      "note": "raw input"
    },
    {
      "from": "ParseInput",
      "to": "parent",
      "data": "action_request",
      "note": "parsed request"
    },
    {
      "from": "parent",
      "to": "RouteAction",
      "data": "action_request",
      "note": "route based on action"
    },
    {
      "from": "RouteAction",
      "to": "TriggerBuild",
      "data": "repo, branch",
      "note": "if action=trigger"
    },
    {
      "from": "RouteAction",
      "to": "CheckStatus",
      "data": "repo, branch",
      "note": "if action=status"
    },
    {
      "from": "RouteAction",
      "to": "ListBuilds",
      "data": "repo",
      "note": "if action=list"
    },
    {
      "from": "RouteAction",
      "to": "CancelBuild",
      "data": "repo, branch",
      "note": "if action=cancel"
    },
    {
      "from": "TriggerBuild",
      "to": "parent",
      "data": "build_result",
      "note": "trigger result"
    },
    {
      "from": "CheckStatus",
      "to": "parent",
      "data": "build_result",
      "note": "status result"
    },
    {
      "from": "ListBuilds",
      "to": "parent",
      "data": "build_result",
      "note": "list result"
    },
    {
      "from": "CancelBuild",
      "to": "parent",
      "data": "build_result",
      "note": "cancel result"
    }
  ]
}
